import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../secretFile.txt";
        String directory = "/var/www/data/";

        if (!isInputValid(userInput)) {
            System.out.println("Invalid input path");
            return;
        }

        File file = new File(directory + userInput);

        try {
            FileInputStream fis = new FileInputStream(file);
            int content;
            while ((content = fis.read()) != -1) {
                System.out.print((char) content);
            }
            fis.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    private static boolean isInputValid(String userInput) {
        // Check if the userInput contains any directory traversal characters
        if (userInput.contains("..") || userInput.contains("/") || userInput.contains("\\")) {
            return false;
        }
        return true;
    }
}

